	import sailpoint.object.Filter;
	import sailpoint.object.Link;
	import sailpoint.object.QueryOptions;
	import sailpoint.tools.GeneralException;
	import sailpoint.api.SailPointContext;
	import sailpoint.api.Terminator;
 
	String appName = "Cerner-Service Now";
	String displayName = "???";
	Filter filter=Filter.ignoreCase(Filter.and(Filter.eq("application.name",appName),Filter.eq("displayName",displayName)));
	QueryOptions qops=new QueryOptions();
	qops.addFilter(filter);
	 
    Terminator terminator = new Terminator(context);
    terminator.setTrace(true);
  
	terminator.deleteObjects(Link.class,qops);
	return "Success";
